                if md2 is None or d2 < md2:
                    md2 = d2
            res_term = md2
        else:
            res_term = 10**9
        opp_term = (ox - nx) * (ox - nx) + (oy - ny) * (oy - ny)
        on_resource = 1 if resources and (nx, ny) in set(resources) else 0
        key = (-(on_resource), res_term, -opp_term, dx, dy)
        if best_key is None or key < best_key:
            best_key = key
            best = (dx, dy)

